const express = require('express');
const crypto = require('crypto');
const { createClient } = require('redis');
const twilio = require('twilio');

const app = express();
app.use(express.json());

const PORT = process.env.PORT || 3000;

const REDIS_URL = process.env.REDIS_URL;
const TWILIO_ACCOUNT_SID = process.env.TWILIO_ACCOUNT_SID;
const TWILIO_AUTH_TOKEN = process.env.TWILIO_AUTH_TOKEN;
const TWILIO_FROM_NUMBER = process.env.TWILIO_FROM_NUMBER;

if (!REDIS_URL || !TWILIO_ACCOUNT_SID || !TWILIO_AUTH_TOKEN || !TWILIO_FROM_NUMBER) {
  throw new Error('Missing required environment variables: REDIS_URL, TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN, TWILIO_FROM_NUMBER');
}

const redis = createClient({ url: REDIS_URL });
redis.on('error', (err) => console.error('Redis error:', err));

const twilioClient = twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

const CODE_TTL_SECONDS = 10 * 60;
const MAX_ATTEMPTS = 10;

function generateCode() {
  return String(Math.floor(Math.random() * 1000000)).padStart(6, '0');
}

function hashCode(code) {
  return crypto.createHash('sha256').update(code).digest('hex');
}

function challengeKey(userId) {
  return `2fa:challenge:${userId}`;
}

app.post('/2fa/send', async (req, res) => {
  try {
    const { userId, phoneNumber } = req.body;

    if (!userId || !phoneNumber) {
      return res.status(400).json({ error: 'userId and phoneNumber are required' });
    }

    const code = generateCode();
    const payload = {
      codeHash: hashCode(code),
      attempts: 0,
      createdAt: Date.now()
    };

    await redis.set(challengeKey(userId), JSON.stringify(payload), { EX: CODE_TTL_SECONDS });

    await twilioClient.messages.create({
      body: `Your verification code is: ${code}`,
      from: TWILIO_FROM_NUMBER,
      to: phoneNumber
    });

    return res.json({ success: true, message: 'Verification code sent' });
  } catch (error) {
    console.error('Send 2FA error:', error);
    return res.status(500).json({ error: 'Failed to send verification code' });
  }
});

app.post('/2fa/verify', async (req, res) => {
  try {
    const { userId, code } = req.body;

    if (!userId || !code) {
      return res.status(400).json({ error: 'userId and code are required' });
    }

    const key = challengeKey(userId);
    const existing = await redis.get(key);

    if (!existing) {
      return res.status(400).json({ error: 'Code expired or not found' });
    }

    const challenge = JSON.parse(existing);

    if (challenge.attempts >= MAX_ATTEMPTS) {
      await redis.del(key);
      return res.status(429).json({ error: 'Too many attempts. Locked out.' });
    }

    if (hashCode(String(code)) === challenge.codeHash) {
      await redis.del(key);
      return res.json({ success: true, accessGranted: true });
    }

    challenge.attempts += 1;

    if (challenge.attempts >= MAX_ATTEMPTS) {
      await redis.del(key);
      return res.status(429).json({ error: 'Too many attempts. Locked out.' });
    }

    await redis.set(key, JSON.stringify(challenge), { EX: CODE_TTL_SECONDS });

    return res.status(401).json({
      success: false,
      accessGranted: false,
      error: 'Invalid code',
      remainingAttempts: MAX_ATTEMPTS - challenge.attempts
    });
  } catch (error) {
    console.error('Verify 2FA error:', error);
    return res.status(500).json({ error: 'Failed to verify code' });
  }
});

